const checkpoints = [];

const reservations = JSON.parse(localStorage.getItem('reservations') || '[]');
const units = JSON.parse(localStorage.getItem('units') || '[]');
const unitSizes = JSON.parse(localStorage.getItem('unit_sizes') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');

const unitById = {};
units.forEach(u => { if (u && u.id) unitById[u.id] = u; });
const sizeById = {};
unitSizes.forEach(s => { if (s && s.id) sizeById[s.id] = s; });
const locById = {};
locations.forEach(l => { if (l && l.id) locById[l.id] = l; });

// Find all locations in ZIP 94110
const locIds94110 = locations.filter(l => l && l.postal_code === '94110').map(l => l.id);

// Candidate units: small, drive-up, available, at ZIP 94110, monthly_rate <= 80
const candidateUnits = units.filter(u => {
  if (!u || !locIds94110.includes(u.location_id) || !u.is_available || !u.has_drive_up_access) return false;
  const size = sizeById[u.unit_size_id];
  if (!size || size.size_category !== 'small') return false;
  if (typeof u.monthly_rate !== 'number' || u.monthly_rate > 80) return false;
  return true;
});

let cheapestRate = null;
candidateUnits.forEach(u => {
  if (typeof u.monthly_rate === 'number') {
    if (cheapestRate === null || u.monthly_rate < cheapestRate) cheapestRate = u.monthly_rate;
  }
});

const cheapestUnitIds = candidateUnits.filter(u => typeof u.monthly_rate === 'number' && u.monthly_rate === cheapestRate).map(u => u.id);

// Qualifying confirmed reservations that match all criteria and use the cheapest qualifying unit
const qualifyingReservations = reservations.filter(r => {
  if (!r || r.status !== 'confirmed') return false;
  const u = unitById[r.unit_id];
  if (!u) return false;
  const loc = locById[u.location_id];
  if (!loc || loc.postal_code !== '94110') return false;
  const size = sizeById[u.unit_size_id];
  if (!size || size.size_category !== 'small') return false;
  if (!u.has_drive_up_access) return false;
  if (typeof r.monthly_rate_at_booking !== 'number' || r.monthly_rate_at_booking > 80) return false;
  if (!r.move_in_date || typeof r.move_in_date !== 'string') return false;
  // Must be some day in April 2026
  if (r.move_in_date.indexOf('2026-04-') !== 0) return false;
  // Ensure it's the cheapest qualifying option
  if (cheapestRate != null && r.monthly_rate_at_booking !== cheapestRate) return false;
  if (cheapestUnitIds.length && !cheapestUnitIds.includes(r.unit_id)) return false;
  return true;
});

// CP1 (0.7): User completed a confirmed reservation for the cheapest qualifying small drive-up unit in 94110 with an April 2026 move-in date
checkpoints.push({ passed: qualifyingReservations.length > 0, weight: 0.7 });

// CP2 (0.3): Move-in date is specifically 2026-04-15
const hasExactDate = qualifyingReservations.some(r => r.move_in_date && r.move_in_date.indexOf('2026-04-15') === 0);
checkpoints.push({ passed: hasExactDate, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const prefs = JSON.parse(localStorage.getItem('preferred_locations') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');

const preferred = prefs[0] || null;
const preferredLoc = preferred ? locations.find(l => l.id === preferred.location_id) : null;

// Candidate locations: within 10 miles, rating >= 4.5, has climate-controlled units
const candidateLocations = locations.filter(l => {
  if (!l) return false;
  if (typeof l.distance_miles_from_search !== 'number' || l.distance_miles_from_search > 10) return false;
  if (!l.has_climate_controlled_units) return false;
  if (typeof l.rating !== 'number' || l.rating < 4.5) return false;
  return true;
});

let maxRating = null;
candidateLocations.forEach(l => {
  if (typeof l.rating === 'number') {
    if (maxRating === null || l.rating > maxRating) maxRating = l.rating;
  }
});

const isPreferredQualifying = !!(preferredLoc && candidateLocations.some(l => l.id === preferredLoc.id));
const isPreferredHighestRated = !!(preferredLoc && maxRating != null && preferredLoc.rating === maxRating);

// CP1 (0.7): Preferred location is one of the qualifying nearby locations (<=10 miles, rating >=4.5, climate controlled)
checkpoints.push({ passed: isPreferredQualifying, weight: 0.7 });

// CP2 (0.3): Preferred location has the highest rating among qualifying locations
checkpoints.push({ passed: isPreferredHighestRated, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const sizeGuideInput = JSON.parse(localStorage.getItem('task3_sizeGuideInput') || 'null');
const rules = JSON.parse(localStorage.getItem('size_guide_rules') || '[]');
const unitSizes = JSON.parse(localStorage.getItem('unit_sizes') || '[]');
const units = JSON.parse(localStorage.getItem('units') || '[]');
const reservations = JSON.parse(localStorage.getItem('reservations') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');

const propertyType = sizeGuideInput && sizeGuideInput.propertyType;
const selectedItemKeys = sizeGuideInput && Array.isArray(sizeGuideInput.selectedItemKeys) ? sizeGuideInput.selectedItemKeys : [];
const isCorrectPropertyType = propertyType === '1_bedroom_apartment';

// Helper: compute recommended unit_size_id using same logic as business rules
function computeRecommendedSizeId(pt, selected) {
  if (!pt) return null;
  const chosen = Array.isArray(selected) ? selected : [];
  const candidates = rules.filter(r => r && r.property_type === pt);
  if (!candidates.length) return null;

  let bestRule = null;
  let bestScore = -1;

  candidates.forEach(rule => {
    const required = Array.isArray(rule.required_items) ? rule.required_items : [];
    if (!required.length) {
      if (!bestRule && bestScore < 0) {
        bestRule = rule;
        bestScore = 0;
      }
      return;
    }
    let matches = 0;
    required.forEach(item => {
      if (chosen.includes(item)) matches++;
    });
    if (matches === required.length && matches >= bestScore) {
      bestScore = matches;
      bestRule = rule;
    }
  });

  if (!bestRule && candidates.length) bestRule = candidates[0];
  return bestRule ? bestRule.recommended_unit_size_id : null;
}

let recommendedSizeId = null;
if (isCorrectPropertyType && selectedItemKeys.length > 0) {
  recommendedSizeId = computeRecommendedSizeId(propertyType, selectedItemKeys);
}

// Find next larger size via sort_order
let nextLargerSizeId = null;
if (recommendedSizeId) {
  const sortedSizes = unitSizes.slice().sort((a, b) => {
    const sa = typeof a.sort_order === 'number' ? a.sort_order : 0;
    const sb = typeof b.sort_order === 'number' ? b.sort_order : 0;
    return sa - sb;
  });
  const idx = sortedSizes.findIndex(s => s.id === recommendedSizeId);
  if (idx !== -1 && idx < sortedSizes.length - 1) {
    nextLargerSizeId = sortedSizes[idx + 1].id;
  }
}

// Location IDs for ZIP 30309
const locIds30309 = locations.filter(l => l && l.postal_code === '30309').map(l => l.id);

// Candidate units: at 30309, of next larger size, available, <= $150
let candidateUnits = [];
if (nextLargerSizeId) {
  candidateUnits = units.filter(u => {
    if (!u || !locIds30309.includes(u.location_id) || !u.is_available) return false;
    if (u.unit_size_id !== nextLargerSizeId) return false;
    if (typeof u.monthly_rate !== 'number' || u.monthly_rate > 150) return false;
    return true;
  });
}

let cheapestRate = null;
candidateUnits.forEach(u => {
  if (typeof u.monthly_rate === 'number') {
    if (cheapestRate === null || u.monthly_rate < cheapestRate) cheapestRate = u.monthly_rate;
  }
});

const unitById = {};
units.forEach(u => { if (u && u.id) unitById[u.id] = u; });
const locById = {};
locations.forEach(l => { if (l && l.id) locById[l.id] = l; });

// Reservations that match the next-larger size, 30309, <=150, confirmed, and cheapest
const qualifyingReservations = reservations.filter(r => {
  if (!r || r.status !== 'confirmed') return false;
  const u = unitById[r.unit_id];
  if (!u || !locIds30309.includes(u.location_id)) return false;
  if (u.unit_size_id !== nextLargerSizeId) return false;
  if (typeof r.monthly_rate_at_booking !== 'number' || r.monthly_rate_at_booking > 150) return false;
  if (cheapestRate != null && r.monthly_rate_at_booking !== cheapestRate) return false;
  return true;
});

// CP1 (0.4): User used the size guide correctly for a 1-bedroom apartment with at least one selected item
checkpoints.push({ passed: isCorrectPropertyType && selectedItemKeys.length > 0, weight: 0.4 });

// CP2 (0.3): There is a confirmed reservation for a unit of the next-larger recommended size at a 30309 location with rate <= $150
checkpoints.push({ passed: qualifyingReservations.length > 0 && !!nextLargerSizeId, weight: 0.3 });

// CP3 (0.3): The reserved unit of that size is the cheapest available option under $150 at 30309
const isCheapest = qualifyingReservations.length > 0 && cheapestRate != null && qualifyingReservations.every(r => typeof r.monthly_rate_at_booking === 'number' && r.monthly_rate_at_booking === cheapestRate);
checkpoints.push({ passed: isCheapest, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reservations = JSON.parse(localStorage.getItem('reservations') || '[]');
const units = JSON.parse(localStorage.getItem('units') || '[]');
const unitSizes = JSON.parse(localStorage.getItem('unit_sizes') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');

const unitById = {};
units.forEach(u => { if (u && u.id) unitById[u.id] = u; });
const sizeById = {};
unitSizes.forEach(s => { if (s && s.id) sizeById[s.id] = s; });
const locById = {};
locations.forEach(l => { if (l && l.id) locById[l.id] = l; });

// Find base 10x10 size to determine "at least 10x10" using sort_order
const size10x10 = unitSizes.find(s => s && s.label === '10x10');
const baseSortOrder = size10x10 && typeof size10x10.sort_order === 'number' ? size10x10.sort_order : null;

// Candidate units in Austin, TX that meet all unit criteria
const candidateUnits = units.filter(u => {
  if (!u || !u.is_available || !u.is_climate_controlled || u.promotion_type !== 'first_month_free') return false;
  const loc = locById[u.location_id];
  if (!loc || loc.city !== 'Austin' || loc.state !== 'TX') return false;
  const size = sizeById[u.unit_size_id];
  if (!size || baseSortOrder == null || typeof size.sort_order !== 'number') return false;
  if (size.sort_order < baseSortOrder) return false; // smaller than 10x10
  if (typeof u.monthly_rate !== 'number' || u.monthly_rate > 180) return false;
  return true;
});

let cheapestRate = null;
candidateUnits.forEach(u => {
  if (typeof u.monthly_rate === 'number') {
    if (cheapestRate === null || u.monthly_rate < cheapestRate) cheapestRate = u.monthly_rate;
  }
});

const cheapestUnitIds = candidateUnits.filter(u => typeof u.monthly_rate === 'number' && u.monthly_rate === cheapestRate).map(u => u.id);

// Qualifying confirmed reservations
const qualifyingReservations = reservations.filter(r => {
  if (!r || r.status !== 'confirmed') return false;
  const u = unitById[r.unit_id];
  if (!u || !cheapestUnitIds.includes(u.id)) return false;
  const loc = locById[u.location_id];
  if (!loc || loc.city !== 'Austin' || loc.state !== 'TX') return false;
  if (!u.is_climate_controlled || u.promotion_type !== 'first_month_free') return false;
  const size = sizeById[u.unit_size_id];
  if (!size || baseSortOrder == null || typeof size.sort_order !== 'number' || size.sort_order < baseSortOrder) return false;
  if (typeof r.monthly_rate_at_booking !== 'number' || r.monthly_rate_at_booking > 180) return false;
  if (!r.move_in_date || typeof r.move_in_date !== 'string') return false;
  // First day of next month given baseline 2026-03-03 is 2026-04-01
  if (r.move_in_date.indexOf('2026-04-01') !== 0) return false;
  // Ensure booked rate matches cheapest candidate rate
  if (cheapestRate != null && r.monthly_rate_at_booking !== cheapestRate) return false;
  return true;
});

// CP1 (0.6): Confirmed reservation for a qualifying Austin climate-controlled 10x10+ unit with First Month Free, rate <=$180, move-in 2026-04-01
checkpoints.push({ passed: qualifyingReservations.length > 0, weight: 0.6 });

// CP2 (0.4): The reserved unit is the least expensive among all qualifying units
const isCheapest = qualifyingReservations.length > 0 && cheapestRate != null && qualifyingReservations.every(r => r.monthly_rate_at_booking === cheapestRate);
checkpoints.push({ passed: isCheapest, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reservations = JSON.parse(localStorage.getItem('reservations') || '[]');
const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const plans = JSON.parse(localStorage.getItem('insurance_plans') || '[]');
const selections = JSON.parse(localStorage.getItem('reservation_insurance_selections') || '[]');

const locById = {};
locations.forEach(l => { if (l && l.id) locById[l.id] = l; });

// Reservations at locations near ZIP 60611 (postal_code exactly 60611)
const reservations60611 = reservations.filter(r => {
  if (!r) return false;
  const loc = locById[r.location_id];
  return !!(loc && loc.postal_code === '60611' && r.status !== 'cancelled');
});

// Active plans with exactly $3,000 coverage
const plans3000 = plans.filter(p => p && p.is_active && p.coverage_amount === 3000);
let minPremium3000 = null;
plans3000.forEach(p => {
  if (typeof p.monthly_premium === 'number') {
    if (minPremium3000 === null || p.monthly_premium < minPremium3000) minPremium3000 = p.monthly_premium;
  }
});

// Selections on 60611 reservations that pick the cheapest $3,000 plan
const successfulSelections = selections.filter(sel => {
  if (!sel) return false;
  const res = reservations60611.find(r => r.id === sel.reservation_id);
  if (!res) return false;
  if (sel.coverage_amount !== 3000) return false;
  const plan = plans.find(p => p && p.id === sel.insurance_plan_id && p.is_active);
  if (!plan || plan.coverage_amount !== 3000) return false;
  if (minPremium3000 == null || sel.monthly_premium !== minPremium3000) return false;
  return true;
});

// CP1 (0.7): For a reservation near 60611, user selected an active plan with exactly $3,000 coverage at the lowest premium among $3,000 plans
checkpoints.push({ passed: successfulSelections.length > 0, weight: 0.7 });

// CP2 (0.3): The associated reservation is marked as having insurance
const reservationIdsWithSuccess = successfulSelections.map(s => s.reservation_id);
const hasInsuranceFlag = reservations60611.some(r => reservationIdsWithSuccess.includes(r.id) && !!r.has_insurance);
checkpoints.push({ passed: hasInsuranceFlag, weight: 0.3 });

return checkoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const cart = JSON.parse(localStorage.getItem('cart') || 'null');
const cartItemsAll = JSON.parse(localStorage.getItem('cart_items') || '[]');
const products = JSON.parse(localStorage.getItem('supplies_products') || '[]');

if (!cart) {
  // No cart, all checkpoints fail
  checkpoints.push({ passed: false, weight: 0.34 });
  checkpoints.push({ passed: false, weight: 0.33 });
  checkpoints.push({ passed: false, weight: 0.33 });
  return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
}

const items = cartItemsAll.filter(ci => ci && ci.cart_id === cart.id);
const subtotal = typeof cart.subtotal === 'number' ? cart.subtotal : 0;

const productById = {};
products.forEach(p => { if (p && p.id) productById[p.id] = p; });

let hasMediumBundle = false;
let hasBubbleWrap = false;
let hasLock = false;

items.forEach(ci => {
  const p = productById[ci.product_id];
  if (!p) return;
  const qty = typeof ci.quantity === 'number' ? ci.quantity : 0;
  if (qty <= 0) return;

  // Medium box bundle: product_type box_bundle_medium, price <= 25
  if (!hasMediumBundle && p.product_type === 'box_bundle_medium' && typeof p.price === 'number' && p.price <= 25) {
    hasMediumBundle = true;
  }

  // Bubble wrap: product_type bubble_wrap, price <= 10
  if (!hasBubbleWrap && p.product_type === 'bubble_wrap' && typeof p.price === 'number' && p.price <= 10) {
    hasBubbleWrap = true;
  }

  // Lock: category Locks & Security, price <= 20
  if (!hasLock && p.category_id === 'locks_security' && typeof p.price === 'number' && p.price <= 20) {
    hasLock = true;
  }
});

// CP1 (0.34): Cart subtotal < $60 and contains a qualifying medium box bundle
checkpoints.push({ passed: subtotal < 60 && hasMediumBundle, weight: 0.34 });

// CP2 (0.33): Cart subtotal < $60 and contains a qualifying bubble wrap item
checkpoints.push({ passed: subtotal < 60 && hasBubbleWrap, weight: 0.33 });

// CP3 (0.33): Cart subtotal < $60 and contains a qualifying lock from Locks & Security
checkpoints.push({ passed: subtotal < 60 && hasLock, weight: 0.33 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const messages = JSON.parse(localStorage.getItem('contact_messages') || '[]');

// Look for a message that matches the required topic, location, and keywords
const matching = messages.filter(m => {
  if (!m) return false;
  if (m.topic !== 'access_hours_and_security') return false;
  if ((m.name || '') !== 'Jordan Lee') return false;
  if ((m.email || '') !== 'jordan.lee@example.com') return false;

  const locName = (m.related_location_name || '').toLowerCase();
  if (locName.indexOf('dallas') === -1 || locName.indexOf('main') === -1) return false;

  const text = (m.message || '').toLowerCase();
  const has24Hour = text.indexOf('24-hour') !== -1 || text.indexOf('24 hour') !== -1;
  const hasVehicleStorage = text.indexOf('vehicle storage') !== -1;
  const hasAfterHours = text.indexOf('after-hours') !== -1 || text.indexOf('after hours') !== -1;
  const hasFees = text.indexOf('fee') !== -1 || text.indexOf('fees') !== -1;

  return has24Hour && hasVehicleStorage && hasAfterHours && hasFees;
});

// CP1 (1.0): A contact message exists with the correct topic, contact info, Dallas Main Street location reference, and all required question keywords
checkpoints.push({ passed: matching.length > 0, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const locations = JSON.parse(localStorage.getItem('locations') || '[]');
const tourSlots = JSON.parse(localStorage.getItem('tour_slots') || '[]');
const appointments = JSON.parse(localStorage.getItem('tour_appointments') || '[]');

// Determine the second Seattle location by distance (as searchLocationsNearby would)
const seattleLocs = locations
  .filter(l => l && l.city === 'Seattle')
  .slice()
  .sort((a, b) => {
    const da = typeof a.distance_miles_from_search === 'number' ? a.distance_miles_from_search : Number.POSITIVE_INFINITY;
    const db = typeof b.distance_miles_from_search === 'number' ? b.distance_miles_from_search : Number.POSITIVE_INFINITY;
    if (da === db) {
      const ra = typeof a.rating === 'number' ? a.rating : 0;
      const rb = typeof b.rating === 'number' ? b.rating : 0;
      return rb - ra;
    }
    return da - db;
  });

const secondSeattle = seattleLocs.length >= 2 ? seattleLocs[1] : null;
const secondSeattleId = secondSeattle ? secondSeattle.id : null;

// Find an appointment at that location with the expected visitor info
const candidateAppointments = appointments.filter(a => {
  if (!a || !secondSeattleId) return false;
  if (a.location_id !== secondSeattleId) return false;
  if (a.visit_type !== 'in_person_tour') return false;
  if (a.status !== 'scheduled') return false;
  if ((a.visitor_name || '') !== 'Alex Morgan') return false;
  if ((a.visitor_phone || '') !== '555-123-4567') return false;
  if ((a.visitor_email || '') !== 'alex.morgan@example.com') return false;
  const slot = tourSlots.find(s => s && s.id === a.tour_slot_id);
  if (!slot) return false;
  const start = slot.start_time || '';
  const datePart = start.split('T')[0];
  if (!datePart || datePart.indexOf('2026-05-') !== 0) return false; // some day in May 2026
  const timePart = (start.split('T')[1] || '').substring(0,5); // HH:MM
  const hour = parseInt(timePart.split(':')[0] || '0', 10);
  // Window 14:00-17:00 (2 PM to 5 PM)
  if (isNaN(hour) || hour < 14 || hour >= 17) return false;
  return true;
});

const chosenAppt = candidateAppointments[0] || null;
const chosenSlot = chosenAppt ? tourSlots.find(s => s && s.id === chosenAppt.tour_slot_id) : null;

// Compute earliest in-person slot in window [14:00,17:00) on that date at the second Seattle location
let earliestSlotStart = null;
if (secondSeattleId && chosenSlot) {
  const chosenDate = (chosenSlot.start_time || '').split('T')[0];
  const relevantSlots = tourSlots.filter(s => {
    if (!s) return false;
    if (s.location_id !== secondSeattleId) return false;
    if (s.visit_type !== 'in_person_tour') return false;
    const start = s.start_time || '';
    const datePart = start.split('T')[0];
    if (datePart !== chosenDate) return false;
    const timePart = (start.split('T')[1] || '').substring(0,5);
    const hour = parseInt(timePart.split(':')[0] || '0', 10);
    if (isNaN(hour) || hour < 14 || hour >= 17) return false;
    return true;
  });
  relevantSlots.forEach(s => {
    if (!earliestSlotStart || s.start_time < earliestSlotStart) {
      earliestSlotStart = s.start_time;
    }
  });
}

// CP1 (0.6): Appointment booked at the second Seattle location, in-person, scheduled in May 2026 between 2:00 PM and 5:00 PM with the expected visitor info
const cp1Passed = !!chosenAppt;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.4): The selected slot is the earliest in-person slot in the 2–5 PM window on that date at that location
const cp2Passed = !!(chosenSlot && earliestSlotStart && chosenSlot.start_time === earliestSlotStart);
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
